<?php
declare(strict_types=1);
require_once dirname(__DIR__).'/includes/cms.php';
$pdo=obtenerConexion();$q=$pdo->query("SELECT a.*,COUNT(DISTINCT da.docente_id) docentes,COUNT(DISTINCT cs.id) secciones,COUNT(DISTINCT i.id) inscritos FROM asignaturas a LEFT JOIN docentes_asignaturas da ON da.asignatura_id=a.id AND da.estado='activo' LEFT JOIN capacitacion_secciones cs ON cs.asignatura_id=a.id LEFT JOIN inscripciones_capacitacion i ON i.asignatura_id=a.id AND i.estado IN('inscrito','pendiente_asignacion') WHERE a.deleted_at IS NULL GROUP BY a.id ORDER BY a.orden,a.nombre");$filas=$q->fetchAll();
cmsCabecera('Capacitaciones','capacitaciones/index.php','CRUD, docentes autorizados, secciones e inscripciones pagadas.');
?><div class="d-flex justify-content-end mb-4"><a class="btn btn-primary text-white" href="editar.php"><i class="mdi mdi-plus"></i> Nueva capacitación</a></div><div class="card card-rounded"><div class="card-body"><div class="table-responsive"><table class="table table-hover align-middle"><thead><tr><th>Capacitación</th><th>Precio</th><th>Estado</th><th>Docentes</th><th>Secciones</th><th>Inscritos</th><th>Acciones</th></tr></thead><tbody><?php foreach($filas as$f):?><tr><td><strong><?=atenea_e($f['nombre'])?></strong><div class="small text-muted"><?=atenea_e($f['codigo'])?> · /<?=atenea_e($f['slug'])?></div></td><td>$<?=number_format((float)$f['precio'],2)?></td><td><span class="badge badge-opacity-<?=$f['activo']&&$f['estado_capacitacion']==='publicada'?'success':'secondary'?>"><?=atenea_e($f['estado_capacitacion'])?><?=$f['activo']?'':' · inactiva'?></span></td><td><?=$f['docentes']?></td><td><?=$f['secciones']?></td><td><?=$f['inscritos']?></td><td class="text-nowrap"><a class="btn btn-sm btn-outline-primary" href="editar.php?id=<?=$f['id']?>">Editar</a> <a class="btn btn-sm btn-outline-info" href="secciones.php?capacitacion_id=<?=$f['id']?>">Secciones</a> <a class="btn btn-sm btn-outline-success" href="inscripciones.php?capacitacion_id=<?=$f['id']?>">Estudiantes</a><form class="d-inline" method="post" action="accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$f['id']?>"><button class="btn btn-sm btn-outline-secondary" name="accion" value="duplicar">Duplicar</button> <button class="btn btn-sm btn-outline-warning" name="accion" value="toggle"><?=$f['activo']?'Desactivar':'Activar'?></button> <button class="btn btn-sm btn-outline-danger" name="accion" value="eliminar" onclick="return confirm('La capacitación se archivará para conservar su historial. ¿Continuar?')">Archivar</button></form></td></tr><?php endforeach;?><?php if(!$filas):?><tr><td colspan="7" class="text-center py-5">No hay capacitaciones.</td></tr><?php endif;?></tbody></table></div></div></div><?php cmsPie();
